module gray_code_counter_4bit (
    input wire clk,
    input wire rst,
    output reg [3:0] gray
    );

reg [3:0] invalid_binary;

always @(posedge clk) begin
    if (rst) begin
        invalid_binary <= 4'b0000;
    end else begin
        invalid_binary <= invalid_binary + 1;
    end
end

always @(*) begin
    gray = (invalid_binary >> 1) ^ invalid_binary;
end

endmodule
